/* Error state */
.error-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 48px;
  color: var(--vscode-errorForeground);
}

.error-state details {
  margin-top: 16px;
  width: 100%;
  max-width: 800px;
}

.error-state summary {
  cursor: pointer;
  color: var(--vscode-textLink-foreground);
}

/* Add comment button */
.add-comment-btn {
  position: absolute;
  left: -24px;
  top: 50%;
  transform: translateY(-50%);
  width: 20px;
  height: 20px;
  border-radius: 50%;
  border: 1px solid var(--vscode-button-border, transparent);
  background: var(--vscode-button-background);
  color: var(--vscode-button-foreground);
  cursor: pointer;
  opacity: 0;
  transition: opacity 0.15s;
  font-size: 14px;
  line-height: 1;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 10;
}

.add-comment-btn.visible,
.add-comment-btn:focus {
  opacity: 1;
}

.add-comment-btn.active {
  opacity: 1;
  background: var(--vscode-button-hoverBackground);
}

.add-comment-btn:hover {
  background: var(--vscode-button-hoverBackground);
}

/* Comment input form */
.comment-input-form {
  background: var(--vscode-editor-background);
  border: 1px solid var(--vscode-input-border);
  border-radius: 6px;
  padding: 12px;
  margin: 8px 16px;
}

.comment-input-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 8px;
  font-size: 12px;
  color: var(--vscode-descriptionForeground);
}

.comment-input-form textarea {
  width: 100%;
  background: var(--vscode-input-background);
  color: var(--vscode-input-foreground);
  border: 1px solid var(--vscode-input-border);
  border-radius: 4px;
  padding: 8px;
  font-family: var(--vscode-font-family);
  font-size: 13px;
  resize: vertical;
  min-height: 60px;
}

.comment-input-form textarea:focus {
  outline: 1px solid var(--vscode-focusBorder);
}

.comment-input-actions {
  display: flex;
  justify-content: flex-end;
  gap: 8px;
  margin-top: 8px;
}

.comment-input-actions button {
  padding: 4px 12px;
  border-radius: 4px;
  cursor: pointer;
  font-size: 12px;
}

.cancel-btn {
  background: transparent;
  border: 1px solid var(--vscode-button-border, var(--vscode-contrastBorder, #666));
  color: var(--vscode-foreground);
}

.cancel-btn:hover {
  background: var(--vscode-list-hoverBackground);
}

.submit-btn {
  background: var(--vscode-button-background);
  border: none;
  color: var(--vscode-button-foreground);
}

.submit-btn:hover {
  background: var(--vscode-button-hoverBackground);
}

.close-btn {
  background: none;
  border: none;
  color: var(--vscode-foreground);
  cursor: pointer;
  font-size: 18px;
  padding: 0;
  line-height: 1;
}

.close-btn:hover {
  color: var(--vscode-errorForeground);
}

/* Comment thread display */
.comment-thread {
  background: var(--vscode-editor-background);
  border-left: 3px solid var(--vscode-activityBarBadge-background, #0078d4);
  margin: 8px 16px;
  padding: 8px 12px;
  border-radius: 0 6px 6px 0;
}

.comment {
  padding: 8px 0;
  border-bottom: 1px solid var(--vscode-panel-border);
}

.comment:last-child {
  border-bottom: none;
}

.comment-header {
  display: flex;
  justify-content: space-between;
  font-size: 11px;
  color: var(--vscode-descriptionForeground);
  margin-bottom: 4px;
}

.comment-location {
  font-weight: 500;
}

.comment-body {
  font-size: 13px;
  line-height: 1.5;
  white-space: pre-wrap;
}

.comment-body.resolved {
  text-decoration: line-through;
  opacity: 0.6;
}

.comment-actions {
  margin-top: 8px;
}

.resolve-btn {
  background: transparent;
  border: 1px solid var(--vscode-button-border, var(--vscode-contrastBorder, #666));
  color: var(--vscode-foreground);
  padding: 2px 8px;
  border-radius: 4px;
  cursor: pointer;
  font-size: 11px;
}

.resolve-btn:hover {
  background: var(--vscode-list-hoverBackground);
}

.resolved-badge {
  font-size: 11px;
  color: var(--vscode-gitDecoration-addedResourceForeground, #3fb950);
}

/* Comment row in table */
.comment-row td {
  padding: 0 !important;
  background: transparent !important;
}

