/* Diff Review Panel Styles */

:root {
  --bg-color: var(--vscode-editor-background);
  --text-color: var(--vscode-editor-foreground);
  --border-color: var(--vscode-panel-border);
  --toolbar-bg: var(--vscode-editorWidget-background);
  --text-secondary: var(--vscode-descriptionForeground);
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  padding: 0;
  background: var(--bg-color);
  color: var(--text-color);
  font-family: var(--vscode-font-family);
  font-size: var(--vscode-font-size);
}

#app {
  display: flex;
  flex-direction: column;
  height: 100vh;
}

/* Toolbar */
#toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 16px;
  background: var(--toolbar-bg);
  border-bottom: 1px solid var(--border-color);
  flex-shrink: 0;
}

#filename {
  font-weight: bold;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

#stats {
  font-size: 12px;
  color: var(--text-secondary);
}

/* Diff Container */
#diff-container {
  flex: 1;
  overflow: auto;
  padding: 16px;
}

/* Loading State */
.loading {
  color: var(--text-secondary);
  text-align: center;
  padding: 48px;
}

/* Placeholder content */
#diff-container pre {
  background: var(--vscode-textBlockQuote-background);
  padding: 16px;
  border-radius: 4px;
  overflow-x: auto;
  font-family: var(--vscode-editor-font-family);
  font-size: var(--vscode-editor-font-size);
  line-height: 1.5;
  white-space: pre-wrap;
  word-break: break-word;
}

#diff-container hr {
  border: none;
  border-top: 1px solid var(--border-color);
  margin: 16px 0;
}

/* Stats styling */
#stats {
  margin-left: 16px;
}

.additions {
  color: var(--vscode-gitDecoration-addedResourceForeground, #3fb950);
  margin-right: 8px;
}

.deletions {
  color: var(--vscode-gitDecoration-deletedResourceForeground, #f85149);
}

/* diff2html base overrides for VSCode integration */
.d2h-wrapper {
  font-family: var(--vscode-editor-font-family);
  font-size: var(--vscode-editor-font-size);
}

.d2h-file-wrapper {
  border: 1px solid var(--border-color);
  border-radius: 4px;
  margin-bottom: 16px;
}

.d2h-file-header {
  background: var(--vscode-editorWidget-background);
  border-bottom: 1px solid var(--border-color);
}

/* Dark theme overrides for diff2html */
.d2h-dark-color-scheme .d2h-file-header {
  background: var(--vscode-editor-background);
  border-color: var(--border-color);
}

.d2h-dark-color-scheme .d2h-code-line {
  background: var(--vscode-editor-background);
}

.d2h-dark-color-scheme .d2h-code-side-line {
  background: var(--vscode-editor-background);
}

.d2h-dark-color-scheme .d2h-code-linenumber {
  background: var(--vscode-editorLineNumber-foreground);
  color: var(--vscode-editorLineNumber-foreground);
}

.d2h-dark-color-scheme .d2h-ins {
  background: rgba(35, 134, 54, 0.2);
}

.d2h-dark-color-scheme .d2h-ins .d2h-code-line-ctn {
  background: rgba(35, 134, 54, 0.2);
}

.d2h-dark-color-scheme .d2h-del {
  background: rgba(248, 81, 73, 0.2);
}

.d2h-dark-color-scheme .d2h-del .d2h-code-line-ctn {
  background: rgba(248, 81, 73, 0.2);
}

.d2h-dark-color-scheme .d2h-info {
  background: var(--vscode-editorWidget-background);
  color: var(--vscode-descriptionForeground);
}

/* Line number hover for comment addition */
.d2h-code-linenumber:hover {
  background: var(--vscode-list-hoverBackground);
}

/* Theme variations */
body.dark {
  /* Dark theme overrides if needed */
}

body.light {
  /* Light theme overrides if needed */
}

/* Empty state */
.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 48px;
  color: var(--text-secondary);
}

.empty-state .icon {
  font-size: 48px;
  margin-bottom: 16px;
  opacity: 0.5;
}

/* Error state */
.error-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 48px;
  color: var(--vscode-errorForeground);
}
